var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"일주일 뒤","JPN":"一週間後","ENG":"One week later","TWN":"一週後","THA":"หนึ่งสัปดาห์ต่อมา","VTN":"Một tuần sau","SCN":"一周以后","DEU":"Eine Woche später","FRA":"Une semaine plus tard"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"카나리아 스쿼드 선수 대기실, 건틀렛 리그 4강 <color=#ffd34c>3시간 전</color>","JPN":"カナリア・スクワッド選手待機室、ガントレットリーグ準決勝戦<color=#ffd34c>3時間前</color>","ENG":"Canary Squad waiting room, <color=#ffd34c>3 hours before</color> the Gauntlet League semifinals","TWN":"金絲雀小隊休息室，聖鎧聯賽4強賽<color=#ffd34c>開始前3小時</color>","THA":"ห้องรับรองหน่วยแคนารี<color=#ffd34c>3 ชั่วโมงก่อน</color>รอบรองชนะเลิศลีกกอนต์เล็ต","VTN":"Phòng chờ của Tiểu Đội Canary, <color=#ffd34c>3 giờ trước</color> trận bán kết Gauntlet League","SCN":"金丝雀小队选手休息室，距离圣铠联赛四强比赛开始还有<color=#ffd34c>3小时</color>","DEU":"Warteraum des Canary Trupps, <color=#ffd34c>3 Stunden vor</color> dem Halbfinale der Fehde-Liga","FRA":"Salle d'attente des joueurs de l'escouade Canari, <color=#ffd34c>3 heures avant</color> la demi-finale de la Compétition"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐야, 카나리아 스쿼드는 어디있어?","JPN":"なんだ、カナリア・スクワッドはどこだ？","ENG":"Huh? Where's Canary Squad?","TWN":"喂，金絲雀小隊人呢？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"설마 또 늦을 생각은 아니겠지? 4강전 사전 인터뷰 있다고 연락 안 해뒀어?","JPN":"まさかまた遅れるんじゃないだろうな？　準決勝戦の前にインタビューがあるって連絡してなかったのか？","ENG":"They're not late again, are they? Didn't you tell them that they had an interview before the match?","TWN":"該不會又要給我遲到？沒人跟他們說4強賽開始前要先受訪嗎？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"다시 연락해봐! 다른 방송보다 뒤쳐지면 안 된다고!","JPN":"もう一度連絡してみろ！　他の番組に遅れを取るわけにはいかないんだ！","ENG":"Call them again! We can't let the other stations interview them first!","TWN":"再去聯絡一下！不能輸給其他節目！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"나 참, 곤란하게 됐군.","JPN":"まったく、困ったものだ。","ENG":"Ugh... This isn't good.","TWN":"真是的，現在情況有點尷尬。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"지금부터 인터뷰를 시작해도 세 사람 분을 따려면 빠듯할 것 같은데.","JPN":"今すぐにインタビューを開始したとしても、3人分撮れるか微妙だぞ。","ENG":"Even if we start the interview now, it would be hard to do all three of them.","TWN":"就算現在開始採訪，三個都要訪問到的話時間會很緊。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"신생팀이 여기까지 올라온 게 얼마만인데, 이런 아이템을 다른 녀석들한테 뺏길 수도 없고.","JPN":"新人チームがここまで勝ち上がってくるなんていつぶりだ？　こんな特ダネを他の連中に取られるわけにはいかない。","ENG":"But it's been ages since a newly founded team managed to come this far. And I can't let a scoop like this go to my competitors!","TWN":"已經多久沒有新人隊伍晉級到前4強，這麼好的題材絕對不能被別人搶走！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"저 떠올랐어요! 감독님! 떠올랐다고요!","JPN":"私、浮かびました！　監督！　浮かんできましたよ！","ENG":"Oh, I got it, Sir! I got it!","TWN":"導演！有了！我想到了！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"뭐야, 갑자기 뭐가 떠올랐다는 거야?","JPN":"何だ、いきなり何が浮かんできたんだ？","ENG":"Huh? You got what?","TWN":"什麼啦，你想到什麼？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"네 개인 방송 시절 영상이 인기 급상승 영상으로 떠오르기라도 한 거야?","JPN":"君の配信者時代の動画が人気急上昇にでもなって浮かんできたのか？","ENG":"Did you get a late award for your early livestreaming days or something?","TWN":"你是想到你個人的直播影片點閱率激增嗎？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아니! 그게 아니라! 물론, 그러면 더 좋겠지만!","JPN":"いいえ！　そうじゃなくて！　もちろん、それだったらもっといいんでしょうけど！","ENG":"No! That's not what I'm talking about! I mean, that would better, to be honest!","TWN":"不是啦！那樣當然也很好！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아무튼 카나리아 애들 인터뷰만 따면 되는 거죠?","JPN":"とにかくカナリアの子たちのインタビューができさえすればいいんですよね？","ENG":"Anyway, all you need is to get interviews with the Canary kids, right?","TWN":"但是，總之只要能採訪到金絲雀就OK吧？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그게 다른 경쟁 방송보다 빨리 라이브로 송출되기만 하면 되는 거고요?","JPN":"それが他の競合番組より早くライブ配信されればいいんですよね？","ENG":"On top of that, you want it to be streamed live faster than the other stations?","TWN":"只要搶先其他節目播出就OK吼？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"어? 어어, 그렇지.","JPN":"え？　まぁ、そうだな。","ENG":"Huh? Y-yeah. That's right.","TWN":"蛤？嗯嗯，沒錯。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"저한테 방법이 있어요! 따라오세요!","JPN":"私にいい案があります！　ついてきてください！","ENG":"Then I got a plan! Follow me!","TWN":"那我有辦法！跟我來！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};